import React, { useState } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Alert,
  Box,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { sendOtp, verifyOtp } from "../services/api"; // make sure your API calls are correct

export default function RiderLogin() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [otpSent, setOtpSent] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSendOtp = async () => {
    setError(""); setSuccess(""); setLoading(true);
    try {
      const res = await sendOtp({ mobile, role: "rider" });
      if (res.data.success) {
        setOtpSent(true);
        setSuccess("OTP sent to your mobile. Please check.");
      }
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Server error. Try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async () => {
    setError(""); setSuccess(""); setLoading(true);
    try {
      const res = await verifyOtp({ mobile, otp, role: "rider" });
      if (res.data.success) {
        setSuccess("Login successful!");
        setTimeout(() => navigate("/rider-dashboard"), 1500); // adjust dashboard route
      }
    } catch (err) {
      console.error(err);
      const msg = err.response?.data?.message || "Server error. Try again.";
      setError(msg.includes("pending approval") ? "Your account is pending admin approval." : msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 4, borderRadius: 3, textAlign: "center", boxShadow: 5 }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>Rider Login</Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <TextField
          fullWidth
          type="tel"
          label="Mobile Number"
          value={mobile}
          onChange={(e) => setMobile(e.target.value)}
          margin="normal"
          inputProps={{ maxLength: 10 }}
          disabled={otpSent}
        />

        {otpSent && (
          <TextField
            fullWidth
            type="number"
            label="OTP"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            margin="normal"
          />
        )}

        <Box sx={{ mt: 3 }}>
          {!otpSent ? (
            <Button
              fullWidth
              variant="contained"
              sx={{ bgcolor: "black", fontWeight: "bold" }}
              onClick={handleSendOtp}
              disabled={loading || !mobile}
            >
              {loading ? <CircularProgress size={24} color="inherit" /> : "Send OTP"}
            </Button>
          ) : (
            <Button
              fullWidth
              variant="contained"
              sx={{ bgcolor: "black", fontWeight: "bold" }}
              onClick={handleVerifyOtp}
              disabled={loading || !otp}
            >
              {loading ? <CircularProgress size={24} color="inherit" /> : "Verify OTP & Login"}
            </Button>
          )}
        </Box>

        <Typography sx={{ mt: 2 }}>
          Don’t have an account?{" "}
          <Button onClick={() => navigate("/rider-register")} sx={{ fontWeight: "bold" }}>
            Sign Up
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
